compliant:
// Compliant: Using proper escaping
public void SearchUser(string username)
{
    string escapedUsername = EscapeLdapSearchFilter(username);
    var filter = "(uid=" + escapedUsername + ")";
    var searcher = new DirectorySearcher();
    searcher.Filter = filter;
    searcher.FindAll();
}

private string EscapeLdapSearchFilter(string filter)
{
    return filter.Replace("(", "\\(").Replace(")", "\\)").Replace("*", "\\*");
}
